const refreshes = new Map<string, Promise<Session>>();

export async function refreshSession(id: string) {
  const pending = refreshes.get(id);
  if (pending) return pending;
  const refresh = requestNewSession(id);
  refreshes.set(id, refresh);
  const session = await refresh;
  refreshes.delete(id);
  return session;
}

const session = await refresh; // throws
refreshes.delete(id);         // never runs
return session;

